mapper.sql:
SELECT '${interval}' AS categories_time, IFNULL(SUM(`value`), 0) AS `value` FROM (
SELECT ma.${reading_field} - mi.${reading_field} AS `value` FROM ( SELECT dv.${reading_field}, dv.time FROM ${item.datatablename} dv WHERE dv.time = ( SELECT MIN(dv.time) AS time FROM ${item.datatablename} dv WHERE DATE_FORMAT(CONVERT_TZ(dv.time, 'UTC', #{timezone_value}), '${dateTimeFormat}') = DATE_FORMAT(DATE_SUB(CONVERT_TZ(UTC_TIMESTAMP(), 'UTC', #{timezone_value}), INTERVAL ${beforeDateTimeValue} ${dateTimeUnit}), '${dateTimeFormat}') ) ) mi CROSS JOIN ( SELECT dv.${reading_field}, dv.time FROM ${item.datatablename} dv WHERE dv.time = ( SELECT ${aggregate_function}(dv.time) AS time FROM ${item.datatablename} dv WHERE DATE_FORMAT(CONVERT_TZ(dv.time, 'UTC', #{timezone_value}), '${dateTimeFormat}') = DATE_FORMAT(DATE_SUB(CONVERT_TZ(UTC_TIMESTAMP(), 'UTC', #{timezone_value}), INTERVAL ${afterDateTimeValue} ${dateTimeUnit}), '${dateTimeFormat}') ) ) ma
) t

mapper.select:
SELECT l.id, CONCAT(d.devicename, " ", e.message) AS event, d.devicename AS hardware, i.icon AS icon_url, DATE_FORMAT(CONVERT_TZ(l.start_date, 'UTC', #{timezone_value}), '%d %b, %Y : %h:%i %p') AS trigger_date, IF( TIMESTAMPDIFF(YEAR, l.start_date, UTC_TIMESTAMP()) > 0, CONCAT(TIMESTAMPDIFF(YEAR, l.start_date, UTC_TIMESTAMP()), " year", IF(TIMESTAMPDIFF(YEAR, l.start_date, UTC_TIMESTAMP()) > 1, "s", "")), IF( TIMESTAMPDIFF(MONTH, l.start_date, UTC_TIMESTAMP()) > 0, CONCAT(TIMESTAMPDIFF(MONTH, l.start_date, UTC_TIMESTAMP()), " month", IF(TIMESTAMPDIFF(MONTH, l.start_date, UTC_TIMESTAMP()) > 1, "s", "")), IF( TIMESTAMPDIFF(DAY, l.start_date, UTC_TIMESTAMP()) > 0, CONCAT(TIMESTAMPDIFF(DAY, l.start_date, UTC_TIMESTAMP()), " day", IF(TIMESTAMPDIFF(DAY, l.start_date, UTC_TIMESTAMP()) > 1, "s", "")), IF( TIMESTAMPDIFF(HOUR, l.start_date, UTC_TIMESTAMP()) > 0, CONCAT(TIMESTAMPDIFF(HOUR, l.start_date, UTC_TIMESTAMP()), " hour", IF(TIMESTAMPDIFF(HOUR, l.start_date, UTC_TIMESTAMP()) > 1, "s", "")), IF( TIMESTAMPDIFF(MINUTE, l.start_date, UTC_TIMESTAMP()) > 0, CONCAT(TIMESTAMPDIFF(MINUTE, l.start_date, UTC_TIMESTAMP()), " minute", IF(TIMESTAMPDIFF(MINUTE, l.start_date, UTC_TIMESTAMP()) > 1, "s", "")), CONCAT(TIMESTAMPDIFF(SECOND, l.start_date, UTC_TIMESTAMP()), " second", IF(TIMESTAMPDIFF(SECOND, l.start_date, UTC_TIMESTAMP()) > 1, "s", "")) ) ) ) ) ) AS opened_period FROM `alert` l LEFT JOIN error e ON e.id = l.id_error LEFT JOIN error_level el ON el.id = e.id_error_level LEFT JOIN icon i ON i.id = el.id_icon LEFT JOIN device d ON d.id = l.id_device LEFT JOIN site s ON s.id = d.id_site WHERE e.status = 1 AND e.is_delete = 0 AND l.status = 1 AND l.is_delete = 0 AND s.enable_alert = 1
#{item.id}
ORDER BY id DESC
